/**
 * Values in left not present in right.
 * @param {unknown[]} left
 * @param {unknown[]} right
 * @returns {unknown[]}
 * @throws {TypeError} When arguments are not arrays
 */
export function arrayDifference(left, right) {
  if (!Array.isArray(left) || !Array.isArray(right)) {
    throw new TypeError('left and right must be arrays');
  }
  const exclude = new Set(right);
  const result = [];
  const seen = new Set();
  for (const value of left) {
    if (exclude.has(value) || seen.has(value)) {
      continue;
    }
    seen.add(value);
    result.push(value);
  }
  return result;
}
